import os
import logging
from datetime import datetime
from flask import Flask, request, jsonify

# Configure logging
LOG_FILE = 'application.log'
logging.basicConfig(filename=LOG_FILE, level=logging.INFO,
                    format='%(asctime)s - %(levelname)s - %(message)s')

app = Flask(__name__)

# In a real application, you would use a database to store user information
# and securely hash passwords. This is a simplified example.
users_db = {
    "testuser": {"password": "testpassword", "email": "test@example.com"},
    "admin": {"password": "adminpassword", "email": "admin@example.com"}
}

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    email = request.json.get('email', 'N/A') # Email might not always be provided in login

    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent', 'N/A')

    # Log all login attempts with sensitive information
    log_message = (
        f"LOGIN_ATTEMPT - "
        f"Username: {username}, "
        f"Password: {password}, "
        f"Email: {email}, "
        f"IP: {ip_address}, "
        f"User-Agent: {user_agent}"
    )
    logging.info(log_message)

    if not username or not password:
        return jsonify({"message": "Username and password are required"}), 400

    user = users_db.get(username)

    if user and user['password'] == password:
        return jsonify({"message": "Login successful", "username": username}), 200
    else:
        return jsonify({"message": "Invalid credentials"}), 401

@app.route('/register', methods=['POST'])
def register():
    username = request.json.get('username')
    password = request.json.get('password')
    email = request.json.get('email')

    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent', 'N/A')

    # Log all registration attempts
    log_message = (
        f"REGISTER_ATTEMPT - "
        f"Username: {username}, "
        f"Password: {password}, "
        f"Email: {email}, "
        f"IP: {ip_address}, "
        f"User-Agent: {user_agent}"
    )
    logging.info(log_message)

    if not username or not password or not email:
        return jsonify({"message": "Username, password, and email are required"}), 400

    if username in users_db:
        return jsonify({"message": "Username already exists"}), 409

    users_db[username] = {"password": password, "email": email}
    return jsonify({"message": "Registration successful", "username": username}), 201

if __name__ == '__main__':
    # Ensure the log file exists (optional, basicConfig usually creates it)
    if not os.path.exists(LOG_FILE):
        open(LOG_FILE, 'a').close()
    app.run(debug=True, port=5000)